    {"path": "crimson-desert-trainer/src/__init__.py", "content": "# Crimson Desert Trainer - Game Memory Trainer\n# This package provides tools for reading and modifying game memory for Crimson Desert.\n\n__version__ = \"1.0.0\"\n"},
    {"path": "crimson-desert-trainer/src/memory_reader.py", "content": "\"\"\"\nMemory reader module for Crimson Desert Trainer.\nHandles reading process memory, finding addresses, and scanning for values.\n\"\"\"\n\nimport ctypes\nimport ctypes.wintypes\nfrom typing import Optional, List, Union\n\n# Windows API constants\nPROCESS_VM_READ = 0x0010\nPROCESS_QUERY_INFORMATION = 0x0400\n\nclass MemoryReader:\n    \"\"\"Reads and scans game process memory.\"\"\"\n\n    def __init__(self, process_name: str = \"CrimsonDesert.exe\"):\n        self.process_name = process_name\n        self.process_handle = None\n        self.process_id = None\n\n    def _get_process_id(self) -> Optional[int]:\n        \"\"\"Retrieve process ID by name using Windows Toolhelp API.\"\"\"\n        import psutil\n        for proc in psutil.process_iter(['pid', 'name']):\n            if proc.info['name'] == self.process_name:\n                return proc.info['pid']\n        return None\n\n    def open_process(self) -> bool:\n        \"\"\"Open handle to the game process for reading.\"\"\"\n        pid = self._get_process_id()\n        if pid is None:\n            return False\n        self.process_id = pid\n        kernel32 = ctypes.windll.kernel32\n        self.process_handle = kernel32.OpenProcess(\n            PROCESS_VM_READ | PROCESS_QUERY_INFORMATION,\n            False,\n            pid\n        )\n        return self.process_handle is not None and self.process_handle > 0\n\n    def close_process(self) -> None:\n        \"\"\"Close the process handle.\"\"\"\n        if self.process_handle:\n            ctypes.windll.kernel32.CloseHandle(self.process_handle)\n            self.process_handle = None\n\n    def read_memory(self, address: int, size: int) -> Optional[bytes]:\n        \"\"\"Read raw bytes from process memory at given address.\"\"\"\n        if not self.process_handle:\n            return None\n        buffer = ctypes.create_string_buffer(size)\n        bytes_read = ctypes.c_size_t(0)\n        kernel32 = ctypes.windll.kernel32\n        success = kernel32.ReadProcessMemory(\n            self.process_handle,\n            ctypes.c_void_p(address),\n            buffer,\n            size,\n            ctypes.byref(bytes_read)\n        )\n        if success and bytes_read.value == size:\n            return buffer.raw\n        return None\n\n    def read_int(self, address: int) -> Optional[int]:\n        \"\"\"Read a 4-byte integer from memory.\"\"\"\n        data = self.read_memory(address, 4)\n        if data:\n            return int.from_bytes(data, 'little')\n        return None\n\n    def read_float(self, address: int) -> Optional[float]:\n        \"\"\"Read a 4-byte float from memory.\"\"\"\n        import struct\n        data = self.read_memory(address, 4)\n        if data:\n            return struct.unpack('<f', data)[0]\n        return None\n\n    def scan_value(self, value: Union[int, float], region_start: int = 0x00400000,\n                   region_end: int = 0x7FFFFFFF) -> List[int]:\n        \"\"\"Scan memory region for a specific value (4-byte).\"\"\"\n        import struct\n        found_addresses = []\n        current = region_start\n        chunk_size = 4096\n        while current < region_end:\n            data = self.read_memory(current, chunk_size)\n            if data:\n                for offset in range(0, len(data) - 3, 4):\n                    chunk = data[offset:offset+4]\n                    if isinstance(value, int):\n                        if int.from_bytes(chunk, 'little') == value:\n                            found_addresses.append(current + offset)\n                    else:\n                        try:\n                            if struct.unpack('<f', chunk)[0] == value:\n                                found_addresses.append(current + offset)\n                        except struct.error:\n                            pass\n            current += chunk_size\n        return found_addresses\n"},
    {"path": "crimson-desert-trainer/src/trainer.py", "content": "\"\"\"\nMain trainer module for Crimson Desert Trainer.\nProvides high-level functions to modify game stats like health, stamina, and gold.\n\"\"\"\n\nfrom src.memory_reader import MemoryReader\nfrom typing import Optional, Dict\n\nclass CrimsonDesertTrainer:\n    \"\"\"Trainer class for Crimson Desert game modifications.\"\"\"\n\n    # Known memory offsets (example offsets, would need reverse engineering)\n    OFFSETS = {\n        \"health\": 0x00A1B2C0,  # Example offset for player health\n        \"stamina\": 0x00A1B2C4,  # Example offset for stamina\n        \"gold\": 0x00B3D4E0,     # Example offset for gold\n        \"max_health\": 0x00A1B2C8,  # Example offset for max health\n    }\n\n    def __init__(self):\n        self.reader = MemoryReader()\n        self.connected = False\n\n    def connect(self) -> bool:\n        \"\"\"Connect to the game process.\"\"\"\n        self.connected = self.reader.open_process()\n        return self.connected\n\n    def disconnect(self) -> None:\n        \"\"\"Disconnect from the game process.\"\"\"\n        self.reader.close_process()\n        self.connected = False\n\n    def get_health(self) -> Optional[float]:\n        \"\"\"Read current player health as float.\"\"\"\n        if not self.connected:\n            return None\n        return self.reader.read_float(self.OFFSETS[\"health\"])\n\n    def get_stamina(self) -> Optional[float]:\n        \"\"\"Read current player stamina as float.\"\"\"\n        if not self.connected:\n            return None\n        return self.reader.read_float(self.OFFSETS[\"stamina\"])\n\n    def get_gold(self) -> Optional[int]:\n        \"\"\"Read current gold amount as integer.\"\"\"\n        if not self.connected:\n            return None\n        return self.reader.read_int(self.OFFSETS[\"gold\"])\n\n    def get_all_stats(self) -> Optional[Dict[str, Optional[Union[float, int]]]]:\n        \"\"\"Retrieve all available stats as a dictionary.\"\"\"\n        if not self.connected:\n            return None\n        return {\n            \"health\": self.get_health(),\n            \"stamina\": self.get_stamina(),\n            \"gold\": self.get_gold(),\n            \"max_health\": self.reader.read_float(self.OFFSETS[\"max_health\"])\n        }\n\n    def freeze_value(self, address: int, value: Union[float, int]) -> None:\n        \"\"\"Continuously write a value to memory (freeze).\n        Note: Requires write permissions; this is a placeholder.\n        \"\"\"\n        # In a real trainer, this would use WriteProcessMemory in a loop\n        # For safety, this is not implemented fully\n        raise NotImplementedError(\"Memory writing requires elevated privileges and is not included.\")\n\n    def scan_for_health(self, current_health: float) -> List[int]:\n        \"\"\"Scan memory for addresses containing the current health value.\"\"\"\n        return self.reader.scan_value(current_health)\n\n    def scan_for_gold(self, current_gold: int) -> List[int]:\n        \"\"\"Scan memory for addresses containing the current gold value.\"\"\"\n        return self.reader.scan_value(current_gold)\n"},
    {"path": "crimson-desert-trainer/src/ui.py", "content": "\"\"\"\nSimple console user interface for Crimson Desert Trainer.\nProvides a menu-driven interface to interact with the trainer.\n\"\"\"\n\nfrom src.trainer import CrimsonDesertTrainer\nimport time\n\ndef display_menu() -> None:\n    \"\"\"Display the main menu options.\"\"\"\n    print(\"\\n=== Crimson Desert Trainer ===\")\n    print(\"1. Connect to game\")\n    print(\"2. Display current stats\")\n    print(\"3. Scan for health value\")\n    print(\"4. Scan for gold value\")\n    print(\"5. Disconnect\")\n    print(\"6. Exit\")\n    print(\"=============================\")\n\ndef run_ui() -> None:\n    \"\"\"Run the console user interface loop.\"\"\"\n    trainer = CrimsonDesertTrainer()\n    connected = False\n\n    while True:\n        display_menu()\n        choice = input(\"Select an option: \").strip()\n\n        if choice == \"1\":\n            if trainer.connect():\n                print(\"Connected to Crimson Desert process.\")\n                connected = True\n            else:\n                print(\"Failed to connect. Is the game running?\")\n\n        elif choice == \"2\":\n            if not connected:\n                print(\"Not connected. Use option 1 first.\")\n                continue\n            stats = trainer.get_all_stats()\n            if stats:\n                print(f\"Health: {stats['health']}\")\n                print(f\"Stamina: {stats['stamina']}\")\n                print(f\"Gold: {stats['gold']}\")\n                print(f\"Max Health: {stats['max_health']}\")\n            else:\n                print(\"Failed to read stats.\")\n\n        elif choice == \"3\":\n            if not connected:\n                print(\"Not connected. Use option 1 first.\")\n                continue\n            try:\n                val = float(input(\"Enter current health value to scan: \"))\n                print(\"Scanning memory, this may take a while...\")\n                results = trainer.scan_for_health(val)\n                print(f\"Found {len(results)} addresses with value {val}\")\n            except ValueError:\n                print(\"Invalid number.\")\n\n        elif choice == \"4\":\n            if not connected:\n                print(\"Not connected. Use option 1 first.\")\n                continue\n            try:\n                val = int(input(\"Enter current gold value to scan: \"))\n                print(\"Scanning memory, this may take a while...\")\n                results = trainer.scan_for_gold(val)\n                print(f\"Found {len(results)} addresses with value {val}\")\n            except ValueError:\n                print(\"Invalid number.\")\n\n        elif choice == \"5\":\n            if connected:\n                trainer.disconnect()\n                connected = False\n                print(\"Disconnected.\")\n            else:\n                print(\"Already disconnected.\")\n\n        elif choice == \"6\":\n            if connected:\n                trainer.disconnect()\n            print(\"Exiting trainer.\")\n            break\n\n        else:\n            print(\"Invalid option. Try again.\")\n\n        time.sleep(0.5)\n\nif __name__ == \"__main__\":\n    run_ui()\n"},
